#[derive(Deserialize)]
struct WebhookQuery {
    url: String,
}

struct AppState {
    client: reqwest::Client,
    allowed_domains: HashSet<String>,
}

impl AppState {
    fn new(allowed_domains: Vec<String>) -> Self {
        let client = reqwest::Client::builder()
            .redirect(Policy::none())
            .timeout(Duration::from_secs(10))
            .connect_timeout(Duration::from_secs(5))
            .build()
            .expect("Failed to create HTTP client");

        Self {
            client,
            allowed_domains: allowed_domains.into_iter().collect(),
        }
    }
}

fn is_private_ip(ip: IpAddr) -> bool {
    match ip {
        IpAddr::V4(ipv4) => {
            ipv4.is_private()
                || ipv4.is_loopback()
                || ipv4.is_link_local()
                || ipv4.is_broadcast()
                || ipv4.is_documentation()
                || ipv4.is_unspecified()
                || ipv4.octets()[0] == 169 && ipv4.octets()[1] == 254
                || ipv4.octets()[0] == 100
                    && (ipv4.octets()[1] >= 64 && ipv4.octets()[1] <= 127)
        }
        IpAddr::V6(ipv6) => {
            ipv6.is_loopback()
                || ipv6.is_unspecified()
                || ((ipv6.segments()[0] & 0xfe00) == 0xfc00)
                || ((ipv6.segments()[0] & 0xffc0) == 0xfe80)
                || ipv6.segments()[0] == 0x2001 && ipv6.segments()[1] == 0xdb8
        }
    }
}

fn validate_url(url_str: &str, allowed_domains: &HashSet<String>) -> Result<Url, String> {
    let url = Url::parse(url_str).map_err(|_| "Invalid URL format".to_string())?;

    if url.scheme() != "http" && url.scheme() != "https" {
        return Err("Only HTTP and HTTPS schemes are allowed".to_string());
    }

    let host = url.host_str().ok_or("URL must have a host")?;

    if !allowed_domains.contains(host) {
        return Err(format!("Domain '{}' is not in the allowlist", host));
    }

    if let Ok(ip) = IpAddr::from_str(host) {
        if is_private_ip(ip) {
            return Err("Private IP addresses are not allowed".to_string());
        }
    }

    if url.username() != "" || url.password().is_some() {
        return Err("URLs with credentials are not allowed".to_string());
    }

    Ok(url)
}

async fn resolve_and_validate_ip(host: &str) -> Result<(), String> {
    let addrs = tokio::net::lookup_host(format!("{}:80", host))
        .await
        .map_err(|_| "Failed to resolve hostname")?;

    for addr in addrs {
        if is_private_ip(addr.ip()) {
            return Err(format!(
                "Hostname '{}' resolves to private IP address",
                host
            ));
        }
    }

    Ok(())
}

async fn webhook_handler(
    axum::extract::State(state): axum::extract::State<std::sync::Arc<AppState>>,
    Query(params): Query<WebhookQuery>,
) -> Result<Response, (StatusCode, String)> {
    let url = validate_url(&params.url, &state.allowed_domains)
        .map_err(|e| (StatusCode::BAD_REQUEST, e))?;

    if let Some(host) = url.host_str() {
        resolve_and_validate_ip(host)
            .await
            .map_err(|e| (StatusCode::BAD_REQUEST, e))?;
    }

    let response = state
        .client
        .get(url.as_str())
        .send()
        .await
        .map_err(|e| (StatusCode::BAD_GATEWAY, format!("Request failed: {}", e)))?;

    if response.status().is_redirection() {
        return Err((
            StatusCode::BAD_REQUEST,
            "Redirects are not allowed".to_string(),
        ));
    }

    let status = response.status();
    let headers = response.headers().clone();
    let body = response
        .bytes()
        .await
        .map_err(|e| (StatusCode::BAD_GATEWAY, format!("Failed to read response: {}", e)))?;

    let mut builder = axum::response::Response::builder().status(status);

    for (key, value) in headers.iter() {
        if key != "transfer-encoding" && key != "connection" {
            builder = builder.header(key, value);
        }
    }

    Ok(builder
        .body(axum::body::Body::from(body))
        .unwrap()
        .into_response())
}

#[tokio::main]
async fn main() {
    let allowed_domains = vec![
        "api.example.com".to_string(),
        "partner.example.org".to_string(),
        "webhook.trusted-service.com".to_string(),
    ];

    let state = std::sync::Arc::new(AppState::new(allowed_domains));

    let app = Router::new()
        .route("/webhook", get(webhook_handler))
        .with_state(state);

    let listener = tokio::net::TcpListener::bind("127.0.0.1:3000")
        .await
        .unwrap();

    println!("Webhook proxy listening on http://127.0.0.1:3000");

    axum::serve(listener, app).await.unwrap();
}